import{_ as c}from"./nyalra_kb-7135827b.js";import{_ as i}from"./nyalra_no_mono-8344e451.js";import{_ as r,W as s,X as p,Y as _,Z as e,$ as a,a0 as t,a2 as d,a1 as f,C as o}from"./framework-a4c02b8f.js";const m={},g=e("figure",null,[e("img",{src:c,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),b={href:"https://tree-novel.com/works/episode/8e00854258ea12da96b089a4e49dcc5d.html",target:"_blank",rel:"noopener noreferrer"},u=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),h=f('<hr><p>在夜晚散步的时候，我突然抬头仰望天空，只见夜空中闪烁着美丽的星星。</p><figure><img src="https://img.tree-novel.com/talk/a29a379bc5f0112754ad7d6ecd3e4a8a.JPG" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>在东京，居然也能看到这么多的星星啊。平时我从来没有去寻找过星星，所以感到非常惊讶。然而，同时我也觉得，仅仅如此而已呢。说起来，我对自然风景的感动感很淡薄。</p><figure><img src="https://img.tree-novel.com/talk/0afc8ad4b768df51bb533cbac7725f2d.PNG" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>我喜欢建筑物。最近，有逛寺庙和教堂的兴趣，同时也喜欢寻找那些稍微复古的街景，这是我日常的乐趣。我喜欢人类用手创造的人造物品。特别是宗教建筑，它们被庄严而巨大地建造出来，是人类为了稍微接近神而建造的，我会对其建筑工作中蕴含的对神的祈祷而心驰神迷。但是，对于自然本身的感动，我几乎没有过。</p><p>也许是因为我出生在冲绳吧？那里的海是碧蓝的，稍稍走一段路就能到达森林，所以我可能已经享受了一生中能感受到的大部分的自然温暖之感。不管是登上山顶，还是进入瀑布，虽然可以理解体验本身的乐趣，但并没有对欣赏风景产生渴望的心情。我曾经花了几个小时从清晨开始攀登一座叫做三峠（三ツ峠）的中等难度山峰，但那时山顶的景色无关紧要，唯一让我满足的是「自己攻克了一座难度较高的山的成就感」。即使将山顶的景色留在照片中，把美丽的景色上传到互联网上，基本上也只会引来「（ ´_ゝ｀）哼」的反应，即使别人看到了也只是「（ ´_ゝ｀）哼」而已吧？毕竟在Google上可以找到无数美丽的风景，外行人特意投稿有什么意义呢？这就是我所思考的。</p><p>相比之下，建筑物的照片却给人一种「原来还有这样的东西！」的震撼感，还能欣赏到摄影者对拍摄方式的执着和差异。比如说，「要用这个角度拍！」这样的想法。还可以从中看出，这个人将这座建筑物视为「想要向大家展示的东西」。而风景则给人一种都差不多的感觉，有时甚至会让人觉得强制性地被迫阅读教科书，仿佛是在说：「对教育有好处吧？感动吧？」这样的错觉。可能说得有点夸张了。总之，大部分时候都只是「（ ´_ゝ｀）哼」的范畴。在中野百老汇散步，欣赏中野百老汇的建筑结构和商业设施也是一种恰到好处地刺激我的大脑的方式。</p><figure><img src="https://img.tree-novel.com/talk/4ef6009b0ad39b8f2687772faaa6e055.JPG" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>总的来说，或许只是因为我不喜欢那种像教科书一样，给人一种在学校里被灌输的正确感觉吧。总有成年人会说：「给孩子看这些东西可以培养他们的感性和修养！」我对这种优秀的精神感到反感。也许这是某种复杂情结的表现吧？不过，我相信一定有一部分网络上的怪人们会同意我的观点。「对美丽而正确的事物过敏」的人肯定存在。有些人看到我上面那张突然抬头看到的星空照片，反而会因为那光芒感到烦躁。但是无需顾虑包括我在内的这种家伙，一点点都不要顾虑。</p><hr><p><img src="'+i+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/c3ca20abe775f3c20a28cceb3fe131d2.JPG" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/937750f4d4947b8494c7fd9b01324f86.JPG" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【画作『不全都是该死的眼科医生吗』（有柘植義春的签名）】『螺旋式（ねじ式）』的令人印象深刻的场景。「不全都是该死的眼科医生吗」的字印得很大的精美画作。精心设计的粉色画框给人带来了迷幻的感觉。把它放在房间里，「眼睛」似乎变得更多了，总有一种被人注视的感觉。</p></blockquote>',13);function k(x,y){const n=o("ExternalLinkIcon"),l=o("RouterLink");return s(),p("div",null,[_(" more "),g,e("p",null,[a("原文链接："),e("a",b,[a("第14回／綺麗な自然の風景コンプレックス"),t(n)])]),e("blockquote",null,[u,e("p",null,[t(l,{to:"/posts/Translate/nyalra_kb_13.html"},{default:d(()=>[a("【奈亚拉面壁自语】第13回｜幸福让人迟钝【230214】")]),_:1})])]),h])}const G=r(m,[["render",k],["__file","nyalra_kb_14.html.vue"]]);export{G as default};
